var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......돌아왔나?","JPN":"……帰ってきたか。","ENG":"So you're back.","TWN":"……回來了？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"너희도 참, 놀 팔자는 아닌 모양이군.","JPN":"まったく。お前らも気楽に遊べる人生とは縁がないんだな。","ENG":"Looks like you don’t know how to have fun either.","TWN":"你們也真是，沒有玩樂的命呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그런가요? 전 나름대로 삶과 일의 밸런스를 잘 잡고 있다고 생각하는데요.","JPN":"そうでしょうか。僕は自分なりにワークライフバランスはとれていると思いますけどね。","ENG":"Really? I thought I maintain a pretty good work-life balance.","TWN":"是嗎？我覺得我工作和生活的平衡保持得很好啊。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......너한테 한 말 아니다.","JPN":"……お前に言ったんじゃないぞ。","ENG":"I wasn’t talking about you.","TWN":"……不是說你。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"도착했군요, 미나 양. 그리고 시윤 군.","JPN":"お帰りなさい、ミナさん。そして、アキヤマ君。","ENG":"Welcome back, Mina. And Shiyoon.","TWN":"你們回來啦？米娜小姐，還有時雲君。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어렵게 일정을 쪼개서 쉬라고 보내놨더니 아니나 다를까 사고를 치고 다니네요.","JPN":"やっとスケジュール調整して休みを与えたのに、案の定やってくれたわね。","ENG":"I go out of my way to give you guys a break, and you still manage to mess things up.","TWN":"好不容易讓你們擠出時間休息，結果不出所料，又闖禍了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"관할권 침해라.......","JPN":"管轄権の侵害か……","ENG":"A violation jurisdiction...","TWN":"侵犯管轄權什麼的……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이제 이 정도는 뭐 놀랍지도 않습니다.","JPN":"これくらいではもう驚きもしません。","ENG":"I’m not even surprised by this sort of thing anymore.","TWN":"我現在都不會感到太驚訝了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"신입인 미나 양은 그렇다 치고, 시윤 군. 자네라도 말렸어야지.","JPN":"新人のミナさんはともかく、アキヤマ君。君は阻止すべきだったわよね。","ENG":"Let’s say you just didn’t know better, Mina. But Shiyoon, you could've stopped her.","TWN":"米娜小姐是新人就算了，但時雲君，你不是應該要阻止她嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"억울합니다, 부사장님. 전 최선을 다했다고요.","JPN":"誤解です、副社長。僕は最善を尽くしましたよ。","ENG":"That’s not fair, ma’am. I tried my best to persuade her.","TWN":"副總，冤枉啊。我真的盡力了！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"코핀 컴퍼니의 사규에는 최선이란 말은 반드시 결과를 동반할 경우에만 사용할 수 있다는 조항이 있다네.","JPN":"コフィンカンパニーの社内規定には、最善という言葉は結果を伴う場合にのみ使用できるという条項があるわよ。","ENG":"According to Coffin Company regulations, you’re only allowed to invoke that argument when you’ve got results to show for it.","TWN":"在科芬公司的社規中，盡力了這種話，只有在達到滿意結果的時候才能說。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"기억해 두도록.","JPN":"肝に銘じるように。","ENG":"Don’t forget that.","TWN":"給我記好了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"잔소리는 이쯤 하도록 하지.","JPN":"説教はこれくらいにしておきましょう。","ENG":"That’s enough lecturing for now.","TWN":"說教就說到這裡吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"다행인지 불행인지, 이번에는 그쪽 관할업체에서도 책임 추궁 따위를 할 여유는 없는 것 같으니까.","JPN":"幸か不幸か、今回は向こうの管轄業者にも責任を問う余裕なんてなさそうですので。","ENG":"For better or worse, the TASKFORCE that has jurisdiction over there seems too preoccupied to press charges on this matter.","TWN":"也不知道是幸運還是不幸，這次管轄企業那邊似乎也沒有追究責任的理由。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"역시....... 예상은 했습니다만.","JPN":"やっぱり……予想はついていましたが……","ENG":"I see... I had a feeling that would be the case.","TWN":"果然……和我預想得一樣。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"조금 전 관리국 공식 채널을 통해 전 세계적인 비상 경보가 발령되었습니다.","JPN":"先ほど、管理局の公式チャンネルで世界中に非常警報が発令されました。","ENG":"Just moments ago, the Administration officially issued a global emergency alert.","TWN":"剛才，管理局通過官方頻道發佈了全球緊急警報。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미나 양과 시윤 군이 마주친 그 정체불명의 함선이 세계 각지에 출현했습니다.","JPN":"ミナさんとアキヤマ君が出くわした、あの正体不明の艦船が世界各地に出現しています。","ENG":"The mysterious ships you two saw appeared all over the world.","TWN":"你們兩個遇到的不明艦船在全世界各地都出現了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그와 동시에 해당 함선을 중심으로 다수의 침식체들이 출현하는 것은 물론......","JPN":"それと同時に、それらの艦船を中心に多数の侵食体も出現。","ENG":"Not only did multiple C.O.'s accompany those ships...","TWN":"同時出現了以艦船為中心的侵蝕體……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"원인불명의 급성 침식 증후군이 발생하고 있습니다.","JPN":"原因不明の急性侵食症候群が発生しています。","ENG":"But we’re also seeing acute cases of Corruption Syndrome with unknown causes.","TWN":"還有不明原因的急性侵蝕症候群。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그 함선들에 대한 정보는 아직 밝혀진 게 없나요?","JPN":"その艦船の正体に関しては、まだ明らかになっていませんか？","ENG":"Do we have any other intel on those ships?","TWN":"現在還沒有關於艦船的明確情報嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......확실하지는 않지만, 아마도 리플레이서가 확보해 둔 로스트 쉽으로 추정하고 있네.","JPN":"……確証はないけど、リプレイサーが確保していたロストシップとみられているわ。","ENG":"It’s not clear, but current estimates say that they may be the Lost Ships the Replacer managed to procure.","TWN":"……目前還不確定，但恐怕是克隆集團籌集的失落艦船。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 지금 중요한 건 그게 아니지. 진짜 문제는.......","JPN":"しかし、今重要なのはそれではないの。本当の問題は……","ENG":"But that's the least of our worries right now. The real problem is...","TWN":"但是現在這個不是重點，真正的問題在於……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이번 이상 현상의 원인으로 추정되는 로스트 쉽을 완전히 파괴하는 게 불가능하다는 거다.","JPN":"今回の異常現象の原因とみられるロストシップを、完全に破壊することが不可能だということだ。","ENG":"It’s impossible to completely destroy the Lost Ships, which are likely causing the current phenomena.","TWN":"推測是這次異常現象主因的失落艦船，沒有辦法完全摧毀。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐라고......?","JPN":"どういうこと……？","ENG":"What?","TWN":"什麼……？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"너희들이 겪은 바와 같이, 물리력으로 해당 함선을 파괴한다고 해도 일정 시간이 지나면 다시 원래대로 복원되어 버린다.","JPN":"お前たちが経験したように、物理的にその艦船を破壊できたとしても、\\n一定時間が経つと再び元の形に戻ってしまう。","ENG":"As you two saw, the ships are capable of restoring themselves even if you destroy them physically.","TWN":"和你們經歷的一樣，就算用武力摧毀了艦船，在一定時間之後又會再度恢復成原狀。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"현재로서는 이를 저지할 수단이 없어.","JPN":"現在、これを阻止する手段がない。","ENG":"Currently, there are no known means of preventing this.","TWN":"目前還無法阻止這個現象。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"일단은 로스트 쉽이 파괴된 동안은 이상 현상이 정지하는 것을 확인했다고 합니다.","JPN":"ひとまず、ロストシップが破壊されている間は異常現象が止まることを確認できたそうです。","ENG":"For now, they say the phenomena pauses while the Lost Ships remain destroyed.","TWN":"暫時可以確定的是，失落艦船毀壞期間異常現象會停止。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그래서 함선이 복원될 때마다 재공격을 하고는 있지만......","JPN":"艦船が復元されるたびに攻撃をしかけてはいますが、","ENG":"So they've had to re-attack the ships whenever they are restored...","TWN":"所以艦船一旦復原就要再次攻擊……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어차피 미봉책일 뿐이죠.","JPN":"一時しのぎでしかありません。","ENG":"Of course, this is only a temporary solution.","TWN":"但這終究是治標不治本。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"거기다가 이쪽의 전력이 약한 곳을 노리고 리플레이서 부대와 간부들이 게릴라전을 벌이고 있어서 상황이 더욱 좋지 않습니다.","JPN":"それに、我が戦力の穴を狙って、リプレイサー部隊や幹部がゲリラ戦を繰り広げているため、\\nさらに状況が悪化しています。","ENG":"To make matters worse, we have Replacer troops and officers waging guerrilla warfare to exploit our weakest spots.","TWN":"更糟的是，克隆集團的部隊和幹部在我們戰鬥力較弱的地方展開了遊擊戰。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"각개격파를 당하고 있는데 전력을 합치는 것도 불가능.......","JPN":"各個撃破されているのに、戦力を集結させるのも不可能……","ENG":"So they’ve managed to divide and conquer while keeping us separated...","TWN":"在被克隆集團各個擊破的情況下，我們也不可能集結戰鬥力。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 그야말로 사면초가로군요.","JPN":"ハハ、これこそ八方塞がりですね。","ENG":"Haha, I guess it couldn’t get any worse than this.","TWN":"哈哈，真是四面楚歌呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"안타깝지만 그 말대로네, 시윤 군.","JPN":"残念だけど、その通りよ。アキヤマ君。","ENG":"Unfortunately, it’s exactly as you put it, Shiyoon.","TWN":"雖然很遺憾，但確實是這樣的呢，時雲君。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"보고에 따르면 로스트 쉽이 만드는 이상현상 지역이 시간이 지남에 따라 점점 넓어지고 있다고 하더군요.","JPN":"報告によると、ロストシップが発生させている異常現象地域が、\\n時間の経過とともに広がっているそうです。","ENG":"According to reports, the areas affected by the Lost Ship phenomena grow larger with time.","TWN":"根據報告，失落艦船造成的異常現象區域正在逐漸擴大。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"계산 결과, 앞으로 3개월 정도 후에는......","JPN":"計算の結果、あと3ヶ月ほどで……","ENG":"Based on calculations, in about three months...","TWN":"經計算，三個月之後……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"극지방을 제외한 육지의 97% 가량이 이상현상의 범위 안에 포함되게 됩니다.","JPN":"極地を除いた陸地の97％ほどが異常現象の範囲内に含まれます。","ENG":"About 97% of all land masses excluding the polar areas will be affected.","TWN":"除了極地外，百分之九十七的陸地都會成為異常現象區域。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런......","JPN":"そんな……","ENG":"That’s...","TWN":"怎麼會……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"CSE 레벨이 올라가는 것도 아니고, 오직 인간에게만 침식 증세가 선별적으로 일어나는 괴현상이기 때문에 기존의 침식 억제 프로토콜도 아무런 쓸모가 없습니다.","JPN":"CSEレベルが上がるわけでもなく、人間にだけ侵食症状が起きる怪現象なので、\\n従来の侵食抑制プロトコルもまるで役に立ちません。","ENG":"The CSE Levels haven’t been changing though. The corruption seems to selectively target humans only. So any existing protocols to subdue the Counterside Effect are now useless.","TWN":"不是CSE等級提高，而是只侵蝕人類的選擇性異常現象，所以既存的侵蝕抑制協定完全派不上用場。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"현재 관리국으로부터 인증, 미인증을 막론하고 모든 태스크포스의 총동원령이 내려진 상태입니다.","JPN":"現在、管理局から認可の有無を問わず、\\nすべてのタスクフォースカンパニーに対して招集命令が出されています。","ENG":"The Administration has ordered the full mobilization of all TASKFORCEs, licensed or not.","TWN":"現在不論有沒有受到管理局認證，所有的特遣勢力都收到了總動員令。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"동원된 병력들은 각자 관할 구역 내의 로스트 쉽을 지속적으로 파괴하는 임무에 투입되고 있다고 하더군요.","JPN":"動員された兵力は、それぞれ管轄区域内のロストシップを継続的に破壊する任務に投入されているそうです。","ENG":"The mobilized troops are being committed to missions for destroying Lost Ships in their respective jurisdictions over and over again.","TWN":"能動員的兵力負責持續破壞各自管轄區域內的失落艦船。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"완전한 해결은 아니더라도, 어떻게든 이상지역의 확장을 늦춰야 하니까요.","JPN":"完全な解決にはならなくても、なんとか異常地域の拡大を食い止めなければなりませんから。","ENG":"Although this isn’t a permanent solution, slowing down the spread is the important thing right now.","TWN":"雖然不能根本解決問題，但不論如何，都要減緩異常區域的擴張速度。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼, 우리도 그곳으로 출동하는 건가?","JPN":"じゃあ、私たちもそこに出動するの？","ENG":"So is that where we're headed?","TWN":"那我們也要出動嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아니요.","JPN":"いいえ。","ENG":"No.","TWN":"不。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......왜?","JPN":"……どうして？","ENG":"Why not?","TWN":"……為什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그야 우리 회사는 이미 전담 구역을 팔아버린 지 오래라서 딱히 관할이랄 게 없으니까요.","JPN":"まあ、うちの会社はとっくに管轄権を売却してしまったので、管轄なんてものはないです。","ENG":"Because this company has already sold off all of its jurisdiction rights a long time ago.","TWN":"因為我們公司早就賣掉了全面負責的區域，現在沒有明確的管轄地。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......왠지 그럴 거라고 생각했어.","JPN":"……なんかそんな予感はしてたよ。","ENG":"I had a feeling that was the case.","TWN":"……我就知道會是這樣。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"공통 관할 구역이 있긴 한데, 거긴 이미 우리 말고도 다른 녀석들로 꽉 찼을 겁니다.","JPN":"共同管轄区域はありますが、そこはすでに他社であふれていると思います。","ENG":"Now there are jointly managed jurisdictions out there, but they're probably already packed with other teams.","TWN":"雖然有共同管轄區域，但我們就算過去，那裡也被其他人擠滿了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그 대신, 우리는 조금 특별한 의뢰를 수행하러 가야 합니다.","JPN":"その代わり、私たちは少し特別な依頼を遂行しなければなりません。","ENG":"So instead, we’ll be carrying out a rather special request from a client.","TWN":"不過相對的，我們得執行一個有些特別的委託。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"의뢰? 이 상황에?","JPN":"依頼？　こんな状況で？","ENG":"A client request? In this mess?","TWN":"委託？在這種狀況下？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그야 관리국도 무시하지 못할 만한 곳에서 들어온 의뢰니까요.","JPN":"まあ、管理局も無視できないところからの依頼ですからね。","ENG":"Let’s just say even the Administration would have to respect this client’s wishes.","TWN":"因為是管理局也無法忽視的地方派來的委託。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"확실하지는 않지만 이번 사건을 해결할 실마리를 찾을 수 있을지도 모릅니다.","JPN":"確証はありませんが、今回の事件を解決できる糸口が見つかるかもしれません。","ENG":"I can’t be certain, but we just might find a lead on how to solve this entire incident.","TWN":"雖然還不確定，但說不定可以找到解決這次事件的線索。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......이런, 벌써 시간이 이렇게 되었군요.","JPN":"……まあ、もうこんな時間ですね。","ENG":"Oh my, look at the time.","TWN":"……哎呀，已經是這個時間了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"의뢰를 돕기 위해 파견된 조력자 두 분이 지정 좌표에서 대기 중입니다.","JPN":"依頼のために派遣された助っ人が2人、指定の座標で待機しています。","ENG":"Two assets will be standing by at the designated coordinates to assist our mission.","TWN":"為了幫助你們完成委託，他們派遣了兩名助手，現在已經在指定座標待命。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"자세한 설명은 조력자들과 접촉한 후에 하도록 하죠.","JPN":"詳しい説明はその二人と接触してからにしましょう。","ENG":"I’ll fill you in on the details once you've made contact with them.","TWN":"詳細情況就等你們遇到助手後再說吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그럼 다들 출동하세요.","JPN":"それでは皆さん、出動してください。","ENG":"Roll out, then.","TWN":"好了，大家出動吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"참고로 태스크포스들의 손발이 묶인 탓에, 침식 정화 작전이 전혀 진행되지 못하고 있는 상황입니다.","JPN":"ちなみに、タスクフォースカンパニーが足止めされているせいで、\\n侵食浄化作戦がまったく進んでいません。","ENG":"By the way, Purification is pretty much at a standstill as the other TASKFORCE units are all preoccupied.","TWN":"作為參考，因為特遣勢力忙於迎戰無法脫身，現在絕對無法進行侵蝕淨化作戰。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"CSE 레벨이 높은 지역을 통과할 때 침식체들과의 전투가 예상되고 있으니, 각별히 주의하시기 바랍니다.","JPN":"CSEレベルの高いエリアを通過する際には、侵食体との戦闘が想定されます。\\nくれぐれも注意してください。","ENG":"You will likely run into C.O.'s when passing through areas with high CSE Levels, so stay on your toes.","TWN":"通過CSE等級高的區域時，有可能會發生與侵蝕體的戰鬥，請大家要特別小心。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};